sql:
SELECT weapon_name, attack_speed
FROM weapons
ORDER BY attack_speed DESC;

SELECT status_effect_name, status_effect_type
FROM status_effects
WHERE healing_over_time > 0;

SELECT 
  (SELECT AVG(attack_speed) FROM attack_types WHERE weapon_category = 'Bite_AI') AS Average_Attack_Speed,
  (SELECT impact_decay_rate FROM impact_decay WHERE attack_id = '1') AS Impact_Decay_Rate;

SELECT attack_id
FROM attack_types
WHERE ignore_invulnerable = 1 AND no_reaction = 0;

SELECT *
FROM weapons
WHERE damage > (
    SELECT AVG(damage)
    FROM weapons
);

SELECT dmg_coef, dmg_coef_head, dmg_coef_crit, dmg_coef_body, dmg_coef_arm, dmg_coef_leg 
FROM damage_coefficients 
WHERE attack_id = (SELECT attack_id FROM weapons WHERE weapon_name = 'Short Sword');

SELECT attack_id, attack_speed
FROM attack_types
ORDER BY attack_id;

SELECT w.weapon_id, w.weapon_name
FROM weapons w
WHERE w.attack_speed > (SELECT AVG(at.attack_speed) FROM attack_types at);

SELECT attack_id, dmg_coef_head
FROM damage_coefficients
WHERE dmg_coef_head > 1.0;

external_knowledge:
- 'relatively swift in attack' means weapons with an attack speed greater than 1.5;
- 'average energy drain' refers to the average stamina cost for using these weapons;
- 'least taxing to the more draining' indicates sorting in descending order of the average stamina cost.

sql:
SELECT w.weapon_name || ' - ' || w.weapon_type AS "Weapon Information"
FROM weapons w
JOIN weapon_affix wa ON w.weapon_id = wa.weapon_id;

SELECT attack_types.attack_id, impact_settings.hit_stun
FROM attack_types
JOIN impact_settings ON attack_types.attack_id = impact_settings.attack_id;

SELECT weapon_name, attack_speed
FROM weapons
WHERE attack_speed > (SELECT AVG(attack_speed) FROM weapons);

SELECT a.attack_id, w.weapon_name
FROM attack_types a
JOIN weapons w ON a.weapon_category = w.weapon_type;

SELECT COUNT(*) 
FROM damage_attributes 
WHERE critical_hit_chance > 0.5 AND affixes = 'Fire';

external_knowledge:
- 'sword' is a metaphor for a weapon primarily used for slashing and thrusting actions; 
- 'hidden secrets' refers to detailed attributes of sword attacks not immediately apparent; 
- 'types of wounds' and 'damage done' are metaphorical expressions for 'damage type' and 'damage coefficient' in the database; 
- 'extra punches' metaphorically describes 'additional damage' added by combat modifiers.

sql:
